select c.codprestamo, c.fecha, c.nrodiasatraso nrodiasatrasofin, c.saldocapital saldocapitalfin    
into #final    
from tcscartera as c with (nolock)    
where c.codprestamo in (select codprestamo from #ptmos)    
and fecha = @fecfin    
    
select tcd.codprestamo,(tcd.saldocapital + tcd.interesvigente + tcd.interesvencido + tcd.interesctaorden + tcd.moratoriovigente + tcd.moratoriovencido + tcd.moratorioctaorden + tcd.cargomora + tcd.otroscargos + tcd.impuestos) saldocapitalini    
into #saldoini    
from tcscarteradet as tcd with (nolock)    
where tcd.codprestamo in (select codprestamo from #ptmos)    
and tcd.fecha = @fecini    
    
select tcd.codprestamo,(tcd.saldocapital + tcd.interesvigente + tcd.interesvencido + tcd.interesctaorden + tcd.moratoriovigente + tcd.moratoriovencido + tcd.moratorioctaorden + tcd.cargomora + tcd.otroscargos + tcd.impuestos) saldocapitalfin    
into #saldofin    
from tcscarteradet as tcd with (nolock)    
where tcd.codprestamo in (select codprestamo from #ptmos)    
and tcd.fecha = @fecfin      
     
select t.codigocuenta, t.fecha, t.montototaltran montocapitaltran    
into #pagos    
from tcstransacciondiaria as t with (nolock)    
where t.codigocuenta in (select codprestamo from #ptmos)    
and fecha >= @fecini    
      
select codigocuenta,sum(totpagos) totpagos    
into #totpagos    
from (    
select codigocuenta, isnull (sum(montocapitaltran),0) totpagos    
from #pagos    
where fecha >= @fecini    
group by codigocuenta    
) a    
group by codigocuenta    
     
 select region,     
 count (distinct codprestamo) nroptamo,    
 sum (totpagos) totpagos,    
 sum(aumentamora) aumentamora,    
 sum(disminuyemora) disminuyemora,    
 sum(saldocapitalini) totsaldoini,    
 sum(saldocapitalfin) totsaldofin,    
 (sum(saldocapitalini)-sum(saldocapitalfin)) tot,    
 ((convert (money,sum(aumentamora))) / (convert (money,count(distinct codprestamo)))) porcentuament,    
 ((convert (money,sum(disminuyemora))) / (convert (money,count(distinct codprestamo)))) porcentdismin,    
 case when (sum(saldocapitalfin) - sum(saldocapitalini)) >= 0 then 0 else  
 ((sum(saldocapitalfin) - sum(saldocapitalini))/sum(saldocapitalini))*(-1) end porcent    
      
 into #acumulado    
 from (     
     
     select p.codprestamo, o.nomoficina, tp.totpagos, p.nrodiasatrasoini, f.nrodiasatrasofin, si.saldocapitalini, sf.saldocapitalfin, z.nombre region    
     ,case when f.nrodiasatrasofin > p.nrodiasatrasoini then 1 else 0 end aumentamora    
     ,case when 0 < tp.totpagos then 1 else 0 end disminuyemora     
     from #ptmos p with(nolock)    
     inner join tcloficinas o with (nolock) on p.codoficina=o.codoficina    
     inner join tclzona z on z.zona=o.zona    
     left outer join #final f on f.codprestamo=p.codprestamo    
      left outer join #saldoini si on si.codprestamo=p.codprestamo    
           left outer join #saldofin sf on sf.codprestamo=p.codprestamo    
     left outer join #totpagos tp on tp.codigocuenta=p.codprestamo    
 ) a    
     
 group by region    
     
 select * from #acumulado where region <> 'Zona corporativo'  and region <> 'Zona Cerradas'  
     
 drop table #final    
 drop table #ptmos    
 drop table #totpagos    
 drop table #pagos    
 drop table #acumulado    
  drop table #saldoini    
 drop table #saldofin    
    
     
     
     
GO